import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const AdGrid = ({ pageNumber = 1 }) => {
  const [squares, setSquares] = useState([]);
  const navigate = useNavigate();

  // Calculate square numbers for this page
  const startSquare = (pageNumber - 1) * 200 + 1;
  const endSquare = pageNumber * 200;

  useEffect(() => {
    // Create mock purchases for testing all pages
    const createMockPurchases = () => {
      const mockPurchases = {};
      
      console.log(`Creating mock data for pages 1-10...`);
      
      for (let page = 1; page <= 10; page++) {
        const pageStart = (page - 1) * 200 + 1;
        console.log(`Page ${page}: squares ${pageStart} to ${pageStart + 199}`);
        
        // Mark a few squares as occupied on each page
        for (let i = 0; i < 5; i++) {
          const squareNum = pageStart + (i * 40);
          mockPurchases[squareNum] = {
            status: 'active',
            businessName: `Test Business ${squareNum}`,
            logoData: '/logo.PNG',
            adText: `Test ad for square ${squareNum}`,
            dealLink: 'https://example.com',
            endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
          };
          console.log(`  - Square ${squareNum} marked as occupied`);
        }
      }
      
      console.log('Total mock squares created:', Object.keys(mockPurchases).length);
      return mockPurchases;
    };

    // Load or create purchases
    let purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
    
    // If no purchases exist, create mock data
    if (Object.keys(purchases).length === 0) {
      console.log('No existing purchases found. Creating mock data...');
      purchases = createMockPurchases();
      localStorage.setItem('squarePurchases', JSON.stringify(purchases));
      console.log('Mock data saved to localStorage');
    } else {
      console.log('Found existing purchases:', Object.keys(purchases).length);
    }

    // 🎯 CRITICAL FIX: Create ALL 200 squares for current page
    const initialSquares = Array.from({ length: 200 }, (_, i) => {
      const squareNumber = startSquare + i;
      const purchase = purchases[squareNumber];
      
      console.log(`Creating square ${squareNumber}, purchase exists:`, !!purchase);
      
      if (purchase && purchase.status === 'active') {
        const endDate = new Date(purchase.endDate);
        const today = new Date();
        
        if (today < endDate) {
          return {
            id: squareNumber,
            isAvailable: false,
            businessName: purchase.businessName,
            logoData: purchase.logoData,
            adText: purchase.adText,
            dealLink: purchase.dealLink,
            endDate: purchase.endDate
          };
        }
      }
      
      // 🎯 ALWAYS return a square (available if no purchase)
      return {
        id: squareNumber,
        isAvailable: true,
        price: '£1/day'
      };
    });
    
    console.log(`Page ${pageNumber}: Created ${initialSquares.length} squares`);
    console.log(`Occupied squares: ${initialSquares.filter(sq => !sq.isAvailable).length}`);
    
    setSquares(initialSquares);
  }, [pageNumber, startSquare]);

  const handleSquareClick = (square) => {
    if (square.isAvailable) {
      navigate('/purchase', { 
        state: { 
          squareNumber: square.id,
          pageNumber: pageNumber 
        } 
      });
    } else {
      window.open(square.dealLink, '_blank');
    }
  };

  // 🎯 DEBUG: Log current page data
  console.log(`Rendering Page ${pageNumber}: ${squares.length} squares`);
  console.log(`Squares range: ${startSquare} to ${endSquare}`);

  return (
    <div className="grid-container">
      <div className="page-info">
        <h3>Page {pageNumber} - Squares {startSquare} to {endSquare}</h3>
        <p>
          {squares.filter(square => !square.isAvailable).length}/200 squares occupied
        </p>
      </div>
      
      <div className="squares-grid">
        {squares.length === 0 ? (
          // 🎯 Show loading state if no squares
          <div style={{textAlign: 'center', padding: '50px', color: '#666'}}>
            Loading squares...
          </div>
        ) : (
          // 🎯 Render all 200 squares
          squares.map(square => (
            <div
              key={square.id}
              className="square"
              onClick={() => handleSquareClick(square)}
              title={!square.isAvailable ? `${square.businessName}\nClick to visit deal` : 'Click to purchase this square'}
            >
              {square.isAvailable ? (
                <>
                  <div className="square-text">BUY THIS SQUARE</div>
                  <div className="square-price">{square.price}</div>
                  <div className="square-number">#{square.id}</div>
                </>
              ) : (
                <img 
                  src={square.logoData || '/logo.PNG'} 
                  alt={square.businessName} 
                  className="occupied-logo" 
                />
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default AdGrid;
